SELECT COUNT(*) 
FROM users 
WHERE updated_by IN (SELECT class_id FROM transaction_classes);

SELECT class_name, description
FROM transaction_classes
WHERE is_active = 1;

SELECT t.transaction_id, p.metric_id
FROM transactions t
INNER JOIN performance_metrics p ON t.class_id = p.class_id;

SELECT tc.class_name, pm.precision AS Highest_Precision
FROM transaction_classes tc
JOIN performance_metrics pm ON tc.class_id = pm.class_id
WHERE pm.precision = (
    SELECT MAX(precision) FROM performance_metrics
);

SELECT transaction_id, class_id, transaction_date, amount, description, status, transaction_type, transaction_source, customer_id, account_number
FROM transactions
WHERE transaction_id = 1;

SELECT COUNT(class_id) AS active_class_count
FROM transaction_classes
WHERE is_active = 1;

SELECT class_id, f1_score
FROM performance_metrics
WHERE metric_id = 1;

SELECT alert_id
FROM alerts
WHERE alert_type = 'precision drop' AND alert_status = 'active';
